export type CrmErrorCode = 'validation_error' | 'not_found' | 'conflict';

export class CrmError extends Error {
  readonly code: CrmErrorCode;

  constructor(code: CrmErrorCode, message: string) {
    super(message);
    this.code = code;
  }
}

const nonEmpty = (value: string, field: string): string => {
  if (typeof value !== 'string') {
    throw new CrmError('validation_error', `${field} must be a string`);
  }
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    throw new CrmError('validation_error', `${field} must be non-empty`);
  }
  return trimmed;
};

const optional = <T>(value: T | undefined, validate: (v: T) => T): T | undefined => {
  if (value === undefined) return undefined;
  return validate(value);
};

const email = (value: string, field: string): string => {
  const trimmed = nonEmpty(value, field);
  const emailLike = /^[^\s@]+@[^\s@]+\.[^\s@]+$/u;
  if (!emailLike.test(trimmed)) {
    throw new CrmError('validation_error', `${field} must be a valid email`);
  }
  return trimmed;
};

const isoDateOnly = (value: string, field: string): string => {
  const trimmed = nonEmpty(value, field);
  const iso = /^\d{4}-\d{2}-\d{2}$/u;
  if (!iso.test(trimmed)) {
    throw new CrmError('validation_error', `${field} must be YYYY-MM-DD`);
  }
  return trimmed;
};

const moneyCents = (value: number, field: string): number => {
  if (typeof value !== 'number' || Number.isNaN(value)) {
    throw new CrmError('validation_error', `${field} must be a number`);
  }
  if (!Number.isInteger(value) || value < 0) {
    throw new CrmError('validation_error', `${field} must be an integer >= 0`);
  }
  return value;
};

export type EntityRefKind = 'company' | 'contact' | 'opportunity';

export type EntityRef = Readonly<{
  kind: EntityRefKind;
  id: string;
}>;

export const createRef = (kind: EntityRefKind, id: string): EntityRef => ({
  kind,
  id: nonEmpty(id, 'id'),
});

export type Company = Readonly<{
  id: string;
  name: string;
  createdAt: string;
}>;

export const createCompany = (input: { id: string; name: string; createdAt: string }): Company => ({
  id: nonEmpty(input.id, 'id'),
  name: nonEmpty(input.name, 'name'),
  createdAt: nonEmpty(input.createdAt, 'createdAt'),
});

export type Contact = Readonly<{
  id: string;
  companyId?: string;
  name: string;
  email?: string;
  createdAt: string;
}>;

export const createContact = (input: {
  id: string;
  companyId?: string;
  name: string;
  email?: string;
  createdAt: string;
}): Contact => ({
  id: nonEmpty(input.id, 'id'),
  companyId: optional(input.companyId, (v) => nonEmpty(v, 'companyId')),
  name: nonEmpty(input.name, 'name'),
  email: optional(input.email, (v) => email(v, 'email')),
  createdAt: nonEmpty(input.createdAt, 'createdAt'),
});

export const opportunityStages = [
  'prospecting',
  'qualified',
  'proposal',
  'negotiation',
  'closed_won',
  'closed_lost',
] as const;

export type OpportunityStage = (typeof opportunityStages)[number];

export const isOpportunityStage = (value: string): value is OpportunityStage =>
  (opportunityStages as readonly string[]).includes(value);

export const isTerminalOpportunityStage = (stage: OpportunityStage): boolean =>
  stage === 'closed_won' || stage === 'closed_lost';

export type OpportunityStageTransition = Readonly<{
  from: OpportunityStage;
  to: OpportunityStage;
  at: string;
}>;

export const opportunityStageTransitions: Readonly<
  Record<OpportunityStage, readonly OpportunityStage[]>
> = {
  prospecting: ['qualified'],
  qualified: ['proposal'],
  proposal: ['negotiation'],
  negotiation: ['closed_won', 'closed_lost'],
  closed_won: [],
  closed_lost: [],
} as const;

export type Opportunity = Readonly<{
  id: string;
  companyId: string;
  name: string;
  valueCents: number;
  stage: OpportunityStage;
  stageHistory: readonly OpportunityStageTransition[];
  createdAt: string;
}>;

export const createOpportunity = (input: {
  id: string;
  companyId: string;
  name: string;
  valueCents: number;
  createdAt: string;
}): Opportunity => ({
  id: nonEmpty(input.id, 'id'),
  companyId: nonEmpty(input.companyId, 'companyId'),
  name: nonEmpty(input.name, 'name'),
  valueCents: moneyCents(input.valueCents, 'valueCents'),
  stage: 'prospecting',
  stageHistory: [],
  createdAt: nonEmpty(input.createdAt, 'createdAt'),
});

export const transitionOpportunityStage = (input: {
  opportunity: Opportunity;
  to: OpportunityStage;
  at: string;
}): Opportunity => {
  const at = nonEmpty(input.at, 'at');
  const from = input.opportunity.stage;
  const allowed = opportunityStageTransitions[from];
  if (!allowed.includes(input.to)) {
    throw new CrmError(
      'validation_error',
      `invalid stage transition: ${from} -> ${input.to}`,
    );
  }

  const transition: OpportunityStageTransition = { from, to: input.to, at };
  return {
    ...input.opportunity,
    stage: input.to,
    stageHistory: [...input.opportunity.stageHistory, transition],
  };
};

export type TaskStatus = 'open' | 'completed';

export type Task = Readonly<{
  id: string;
  ref: EntityRef;
  title: string;
  dueDate?: string;
  status: TaskStatus;
  createdAt: string;
  completedAt?: string;
}>;

export const createTask = (input: {
  id: string;
  ref: EntityRef;
  title: string;
  dueDate?: string;
  createdAt: string;
}): Task => ({
  id: nonEmpty(input.id, 'id'),
  ref: input.ref,
  title: nonEmpty(input.title, 'title'),
  dueDate: optional(input.dueDate, (v) => isoDateOnly(v, 'dueDate')),
  status: 'open',
  createdAt: nonEmpty(input.createdAt, 'createdAt'),
});

export const completeTask = (input: { task: Task; completedAt: string }): Task => {
  if (input.task.status === 'completed') {
    throw new CrmError('validation_error', 'task already completed');
  }
  return {
    ...input.task,
    status: 'completed',
    completedAt: nonEmpty(input.completedAt, 'completedAt'),
  };
};

export type Note = Readonly<{
  id: string;
  ref: EntityRef;
  body: string;
  createdAt: string;
}>;

export const createNote = (input: { id: string; ref: EntityRef; body: string; createdAt: string }): Note => ({
  id: nonEmpty(input.id, 'id'),
  ref: input.ref,
  body: nonEmpty(input.body, 'body'),
  createdAt: nonEmpty(input.createdAt, 'createdAt'),
});

import {
  CrmError,
  type Company,
  type Contact,
  type EntityRef,
  type Note,
  type Opportunity,
  type OpportunityStage,
  type Task,
  createCompany,
  createContact,
  createNote,
  createOpportunity,
  createTask,
  isTerminalOpportunityStage,
  opportunityStages,
  transitionOpportunityStage,
  completeTask as completeTaskDomain,
} from '../../domain/src/index.js';

export type DashboardSummary = Readonly<{
  totals: Readonly<{
    companies: number;
    contacts: number;
    opportunities: number;
    openTasks: number;
    overdueTasks: number;
  }>;
  opportunitiesByStage: Readonly<Record<OpportunityStage, number>>;
  pipelineValueCents: number;
}>;

const isoDateOnly = (value: string): string => {
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    throw new CrmError('validation_error', 'asOfDate must be non-empty');
  }
  if (!/^\d{4}-\d{2}-\d{2}$/u.test(trimmed)) {
    throw new CrmError('validation_error', 'asOfDate must be YYYY-MM-DD');
  }
  return trimmed;
};

const keyOf = (ref: EntityRef): string => `${ref.kind}:${ref.id}`;

const assertNever = (value: never): never => {
  // Should be unreachable due to `EntityRefKind` union
  void value;
  throw new CrmError('validation_error', 'unknown ref kind');
};

export class CrmService {
  private readonly companies = new Map<string, Company>();
  private readonly contacts = new Map<string, Contact>();
  private readonly opportunities = new Map<string, Opportunity>();
  private readonly tasks = new Map<string, Task>();
  private readonly notesByRef = new Map<string, Note[]>();

  createCompany(input: { id: string; name: string; createdAt: string }): Company {
    const company = createCompany(input);
    if (this.companies.has(company.id)) {
      throw new CrmError('conflict', `company already exists: ${company.id}`);
    }
    this.companies.set(company.id, company);
    return company;
  }

  getCompany(id: string): Company {
    const company = this.companies.get(id);
    if (!company) throw new CrmError('not_found', `company not found: ${id}`);
    return company;
  }

  createContact(input: {
    id: string;
    companyId?: string;
    name: string;
    email?: string;
    createdAt: string;
  }): Contact {
    const contact = createContact(input);
    if (this.contacts.has(contact.id)) {
      throw new CrmError('conflict', `contact already exists: ${contact.id}`);
    }
    if (contact.companyId !== undefined && !this.companies.has(contact.companyId)) {
      throw new CrmError('not_found', `company not found: ${contact.companyId}`);
    }
    this.contacts.set(contact.id, contact);
    return contact;
  }

  getContact(id: string): Contact {
    const contact = this.contacts.get(id);
    if (!contact) throw new CrmError('not_found', `contact not found: ${id}`);
    return contact;
  }

  createOpportunity(input: {
    id: string;
    companyId: string;
    name: string;
    valueCents: number;
    createdAt: string;
  }): Opportunity {
    const opportunity = createOpportunity(input);
    if (this.opportunities.has(opportunity.id)) {
      throw new CrmError('conflict', `opportunity already exists: ${opportunity.id}`);
    }
    if (!this.companies.has(opportunity.companyId)) {
      throw new CrmError('not_found', `company not found: ${opportunity.companyId}`);
    }
    this.opportunities.set(opportunity.id, opportunity);
    return opportunity;
  }

  getOpportunity(id: string): Opportunity {
    const opportunity = this.opportunities.get(id);
    if (!opportunity) throw new CrmError('not_found', `opportunity not found: ${id}`);
    return opportunity;
  }

  transitionOpportunityStage(input: { id: string; to: OpportunityStage; at: string }): Opportunity {
    const current = this.getOpportunity(input.id);
    if (isTerminalOpportunityStage(current.stage)) {
      throw new CrmError(
        'validation_error',
        `opportunity is terminal (${current.stage}) and cannot transition`,
      );
    }
    const updated = transitionOpportunityStage({
      opportunity: current,
      to: input.to,
      at: input.at,
    });
    this.opportunities.set(updated.id, updated);
    return updated;
  }

  createTask(input: {
    id: string;
    ref: EntityRef;
    title: string;
    dueDate?: string;
    createdAt: string;
  }): Task {
    const task = createTask(input);
    if (this.tasks.has(task.id)) {
      throw new CrmError('conflict', `task already exists: ${task.id}`);
    }
    this.assertRefExists(task.ref);
    this.tasks.set(task.id, task);
    return task;
  }

  getTask(id: string): Task {
    const task = this.tasks.get(id);
    if (!task) throw new CrmError('not_found', `task not found: ${id}`);
    return task;
  }

  completeTask(input: { id: string; completedAt: string }): Task {
    const task = this.getTask(input.id);
    const updated = completeTaskDomain({ task, completedAt: input.completedAt });
    this.tasks.set(updated.id, updated);
    return updated;
  }

  addNote(input: { id: string; ref: EntityRef; body: string; createdAt: string }): Note {
    const note = createNote(input);
    this.assertRefExists(note.ref);
    const key = keyOf(note.ref);
    const existing = this.notesByRef.get(key) ?? [];
    this.notesByRef.set(key, [...existing, note]);
    return note;
  }

  listNotes(ref: EntityRef): readonly Note[] {
    return this.notesByRef.get(keyOf(ref)) ?? [];
  }

  getDashboardSummary(asOfDate: string): DashboardSummary {
    const asOf = isoDateOnly(asOfDate);

    const openTasks = [...this.tasks.values()].filter((t) => t.status === 'open');
    const overdueTasks = openTasks.filter((t) => t.dueDate !== undefined && t.dueDate < asOf);

    const opportunitiesByStage = Object.fromEntries(
      opportunityStages.map((stage) => [
        stage,
        [...this.opportunities.values()].filter((o) => o.stage === stage).length,
      ]),
    ) as Record<OpportunityStage, number>;

    const pipelineValueCents = [...this.opportunities.values()]
      .filter((o) => !isTerminalOpportunityStage(o.stage))
      .reduce((sum, o) => sum + o.valueCents, 0);

    return {
      totals: {
        companies: this.companies.size,
        contacts: this.contacts.size,
        opportunities: this.opportunities.size,
        openTasks: openTasks.length,
        overdueTasks: overdueTasks.length,
      },
      opportunitiesByStage,
      pipelineValueCents,
    };
  }

  private assertRefExists(ref: EntityRef): void {
    switch (ref.kind) {
      case 'company': {
        if (!this.companies.has(ref.id)) {
          throw new CrmError('not_found', `company not found: ${ref.id}`);
        }
        return;
      }
      case 'contact': {
        if (!this.contacts.has(ref.id)) {
          throw new CrmError('not_found', `contact not found: ${ref.id}`);
        }
        return;
      }
      case 'opportunity': {
        if (!this.opportunities.has(ref.id)) {
          throw new CrmError('not_found', `opportunity not found: ${ref.id}`);
        }
        return;
      }
      default: {
        return assertNever(ref);
      }
    }
  }
}

import { describe, expect, test } from 'vitest';
import { CrmService } from '../src/index.js';
import { createRef } from '../../domain/src/index.js';

describe('CrmService', () => {
  test('enforces referential integrity for opportunities', () => {
    const service = new CrmService();
    expect(() =>
      service.createOpportunity({
        id: 'opp_1',
        companyId: 'co_missing',
        name: 'Deal',
        valueCents: 500_00,
        createdAt: 't0',
      }),
    ).toThrow(/company not found/i);
  });

  test('produces deterministic dashboard summary', () => {
    const service = new CrmService();
    service.createCompany({ id: 'co_1', name: 'Acme', createdAt: 't0' });
    service.createContact({ id: 'ct_1', companyId: 'co_1', name: 'Alex', createdAt: 't0' });

    service.createOpportunity({
      id: 'opp_1',
      companyId: 'co_1',
      name: 'Deal 1',
      valueCents: 100_00,
      createdAt: 't0',
    });

    service.createOpportunity({
      id: 'opp_2',
      companyId: 'co_1',
      name: 'Deal 2',
      valueCents: 200_00,
      createdAt: 't0',
    });

    service.transitionOpportunityStage({ id: 'opp_2', to: 'qualified', at: 't1' });

    service.createTask({
      id: 'task_1',
      ref: createRef('company', 'co_1'),
      title: 'Follow up',
      dueDate: '2026-04-10',
      createdAt: 't0',
    });

    const summary = service.getDashboardSummary('2026-04-14');

    expect(summary.totals.companies).toBe(1);
    expect(summary.totals.contacts).toBe(1);
    expect(summary.totals.opportunities).toBe(2);
    expect(summary.opportunitiesByStage.prospecting).toBe(1);
    expect(summary.opportunitiesByStage.qualified).toBe(1);
    expect(summary.pipelineValueCents).toBe(300_00);
    expect(summary.totals.openTasks).toBe(1);
    expect(summary.totals.overdueTasks).toBe(1);
  });
});

import { describe, expect, test } from 'vitest';
import { createOpportunity, transitionOpportunityStage } from '../src/index.js';

describe('opportunity stage transitions', () => {
  test('allows prospecting -> qualified', () => {
    const opportunity = createOpportunity({
      id: 'opp_1',
      companyId: 'co_1',
      name: 'Deal',
      valueCents: 100_00,
      createdAt: 't0',
    });

    const updated = transitionOpportunityStage({
      opportunity,
      to: 'qualified',
      at: 't1',
    });

    expect(updated.stage).toBe('qualified');
    expect(updated.stageHistory).toEqual([{ from: 'prospecting', to: 'qualified', at: 't1' }]);
  });

  test('rejects skipping stages', () => {
    const opportunity = createOpportunity({
      id: 'opp_1',
      companyId: 'co_1',
      name: 'Deal',
      valueCents: 100_00,
      createdAt: 't0',
    });

    expect(() =>
      transitionOpportunityStage({
        opportunity,
        to: 'proposal',
        at: 't1',
      }),
    ).toThrow(/invalid stage transition/i);
  });
});

